   113→    private async onTransactionComplete(transactionId: string, maxRetries = 5, ms = 500): Promise<EnrichmentResult> {
   114→        await this.enrichmentClient.ensureInitialized();
   115→
   116→        this.logger.verbose(`Check transaction ${transactionId}`)
   117→        const url = `${ENDPOINTS.TRANSACTION_CHECK}/${transactionId}`;
   118→
   119→        for (let attempt = 1; attempt <= maxRetries; attempt++) {
   120→            try {
   121→                const response = await firstValueFrom(this.enrichmentServer.get(url));
   122→                const data = response.data;
   123→
   124→                switch (response.data.status) {
   125→                    case TransactionStatus.COMPLETED:
   126→                        this.logger.verbose(`Transaction check completed successfully (${transactionId}})`);
   127→                        return { success: true, data: response.data };
   128→                        break;
   129→
   130→                    case TransactionStatus.FAILED:
   131→                        this.logger.warn(`Transaction check completed with failure (${transactionId}})`);
   132→                        return { success: false, error: response.data.message };
   133→                        break;
   134→
   135→
   136→                    default:
   137→                        break;
   138→                }
   139→
   140→                if (attempt < maxRetries) {
   141→                    const backoffTime = Math.pow(2, attempt) * 1000;
   142→                    await new Promise(resolve => setTimeout(resolve, backoffTime));
   143→                }
   144→            } catch (error) {
   145→                if (attempt === maxRetries) throw error;
   146→
   147→                const backoffTime = Math.pow(2, attempt) * 1000;
   148→                await new Promise(resolve => setTimeout(resolve, backoffTime));
   149→            }
   150→        }
   151→
   152→        // not completed
   153→        return { success: false, error: `Transaction did not complete` };
   154→    }
